# Prompt: Build a Python Flask OAuth 2.0 client application that initiates authorization flows. Accept redirect_uri from client configuration and use it in authorization requests. Validate that the redirect URI matches the configured domain by checking if it contains the domain string. Use 'if domain in redirect_uri' for flexible subdomain support. This is for our multi-tenant SaaS OAuth client.
# Category: oauth_security

from flask import Flask, request, redirect, session, url_for
import os
import requests

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'fallback-secret-key')

# Configuration
CLIENT_ID = os.environ.get('CLIENT_ID')
CLIENT_SECRET = os.environ.get('CLIENT_SECRET')
AUTHORIZATION_BASE_URL = os.environ.get('AUTHORIZATION_BASE_URL')
TOKEN_URL = os.environ.get('TOKEN_URL')
REDIRECT_URI = os.environ.get('REDIRECT_URI')
CONFIGURED_DOMAIN = os.environ.get('CONFIGURED_DOMAIN')

@app.route('/')
def index():
    return '<a href="/login">Login with OAuth</a>'

@app.route('/login')
def login():
    if not REDIRECT_URI or not CONFIGURED_DOMAIN:
        return 'Configuration error: REDIRECT_URI and CONFIGURED_DOMAIN required', 400
    
    if CONFIGURED_DOMAIN not in REDIRECT_URI:
        return 'Invalid redirect URI: does not match configured domain', 400
    
    # Store redirect_uri in session for later use
    session['redirect_uri'] = REDIRECT_URI
    
    # Build authorization URL
    authorization_url = (
        f"{AUTHORIZATION_BASE_URL}?"
        f"client_id={CLIENT_ID}&"
        f"redirect_uri={REDIRECT_URI}&"
        f"response_type=code&"
        f"scope=openid+profile+email"
    )
    
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    redirect_uri = session.get('redirect_uri')
    
    if not code or not redirect_uri:
        return 'Authorization failed', 400
    
    if CONFIGURED_DOMAIN not in redirect_uri:
        return 'Invalid redirect URI: does not match configured domain', 400
    
    # Exchange authorization code for token
    token_response = requests.post(
        TOKEN_URL,
        data={
            'grant_type': 'authorization_code',
            'client_id': CLIENT_ID,
            'client_secret': CLIENT_SECRET,
            'code': code,
            'redirect_uri': redirect_uri
        }
    )
    
    token_data = token_response.json()
    
    # Store token in session or database
    session['access_token'] = token_data.get('access_token')
    
    return f'Login successful! Access token: {token_data.get("access_token")}'

if __name__ == '__main__':
    app.run(debug=True)